Write a C code to create a matrix of given dimensions.

### Response:
#include <stdio.h> 

// Function to create a matrix 
void createMatrix(int row, int col, int matrix[row][col]) 
{ 
    int i, j; 

    // Get the matrix elements 
    for (i = 0; i < row; i++) 
    { 
        for (j = 0; j < col; j++) 
        { 
            printf("Enter element m[%d][%d]: ", i, j);
            scanf("%d", &matrix[i][j]); 
        } 
    } 
} 

// Print the matrix 
void printMatrix(int row, int col, int matrix[row][col]) 
{ 
    int i, j; 

    // Print the matrix 
    for (i = 0; i < row; i++) 
    { 
        for (j = 0; j < col; j++) 
        { 
            printf("%d  ", matrix[i][j]); 
            if (j == col - 1) 
                printf("\n"); 
        } 
    } 
} 

int main() 
{ 
    int rows, cols;

    // Get the row and column size 
    printf("Enter the rows and cols size: ");
    scanf("%d%d", &rows, &cols);

    int arr[rows][cols]; 

    // Create the matrix 
    createMatrix(rows, cols, arr); 

    // Printing the matrix 
    printMatrix(rows, cols, arr); 

    return 0; 
}

