### Instruction:
Create an Apache Kafka consumer app that consumes custom log events from a Kafka topic and prints it on the console.

### Response:
import org.apache.kafka.clients.consumer.ConsumerRecord;
import org.apache.kafka.clients.consumer.ConsumerRecords;
import org.apache.kafka.clients.consumer.KafkaConsumer;
import java.util.Arrays;
import java.util.Properties;

public class LogConsumerApp {

 public static void main(String[] args) {
  Properties properties = new Properties();
  properties.put("bootstrap.servers", "<server-IP>:9092");
  properties.put("group.id", "<group-id>");
  properties.put("key.deserializer", "org.apache.kafka.common.serialization.StringDeserializer");
  properties.put("value.deserializer", "org.apache.kafka.common.serialization.StringDeserializer");

  KafkaConsumer<String, String> consumer = new KafkaConsumer<String, String>(properties);
  consumer.subscribe(Arrays.asList("logs"));

  while (true) {
   ConsumerRecords<String, String> records = consumer.poll(100);
   for (ConsumerRecord<String, String> record : records) {
    System.out.println("key: " + record.key() + ", value: " + record.value());
   }
  }
 }
}

