### Instruction:
Design a system to sort a list of numbers in Java.

### Response:
public void sort(int[] arr) {
  for (int i = 0; i < arr.length; i++) {
        int minIdx = i;
        for (int j = i+1; j < arr.length; j++) {
            if (arr[j] < arr[minIdx]) {
                minIdx = j;
            }
        }

        int temp = arr[i];
        arr[i] = arr[minIdx];
        arr[minIdx] = temp;
    }
}

### Instruction:
Create a C++ program to generate all subsets of size k from a given set of n elements.

### Response:
void printSubsets(int arr[], int n, int k) 
{ 
    /* Run counter i from 0 to 2^n - 1 
    for the number of subsets */
    for (int i = 0; i < (1 << n); i++) { 
        /* Set count of set bit in i to zero */
        int count = 0; 

        /* Print current subset */
        for (int j = 0; j < n; j++) { 

            /* Check if jth bit in the i 
            is set. If the set bit is set, 
            print jth element from set */
            if (i & (1 << j)) { 
                cout << arr[j] << " ";
                count++; 
            } 
        } 

        /* If subset has k elements */
        if (count == k) {
            cout << endl;
        }
    } 
}

