// Todo list React component
import React, { useState } from 'react';
const TodoList = () => {
 const [todos, setTodos] = useState([]);

 const addTodo = todo => {
 setTodos([...todos, todo]);
 };

 const deleteTodo = index => {
 setTodos(todos.filter((todo, i) => i !== index));
 };

 const editTodo = (index, todo) => {
 let updatedTodos = [...todos];
 updatedTodos[index] = todo;
 setTodos(updatedTodos);
 };

 return (
 <div className="TodoList">
 <h1>Todo List</h1>
 <ul>
 {todos.map((todo, i) => (
 <li key={i}>
 <TodoForm
 todo={todo}
 deleteTodo={() => deleteTodo(i)}
 updateTodo={todo => editTodo(i, todo)}
 />
 </li>
 ))}
 </ul>
 <TodoForm addTodo={addTodo} />
 </div>
 );
};

const TodoForm = ({ todo, addTodo, deleteTodo, updateTodo }) => (
 <form>
 <input
 type="text"
 value={todo.description}
 placeholder="Add todo"
 onChange={e => updateTodo({ description: e.target.value })}
 />
 {todo.description && (
 <button type="button" onClick={deleteTodo}>
 X
 </button>
 )}
 {!todo.description && (
 <button type="submit" onClick={addTodo}>
 Add
 </button>
 )}
 </form>
);

export default TodoList;

### Instruction:
Develop a C++ program to check if a linked list contains a cycle.

### Response:
#include <iostream>

// define a single-linked list node structure
struct Node { 
    int data; 
    struct Node* next; 
}; 

// function to detect loop in the linked list 
bool detectLoop(struct Node* h) 
{ 
    struct Node *slow = h, *fast = h; 

    while (slow && fast && fast->next) { 
        slow = slow->next; 
        fast = fast->next->next; 

        if (slow == fast) 
            return true; 
    } 
    return false; 
} 

int main() {
    struct Node* head =  new Node; 
    int x;
    std::cin >> x;

    // input and constructing a single linked list
    while (x != -1) {
        head->data = x; 
        head->next = new Node; 
        head = head->next; 
        std::cin >> x; 
    }
    head->next = NULL; 

    // check if the linked list contains a cycle
    if (detectLoop(head))
        std::cout << "This linked list has a cycle.\n";
    else 
        std::cout << "This linked list does not have a cycle.\n";

    return 0;
}

